function process(input) {
  var state = "0";
  while (true) {
    switch (state) {
      case "0":
        var x = input * 2;
        state = "1";
        break;
      case "1":
        var y = x + 10;
        state = "2";
        break;
      case "2":
        var z = y - 5;
        state = "3";
        break;
      case "3":
        return z;
    }
  }
}
process(7);
